sys_script_client.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if (isLoading || newValue === '') {
		return;
	}
	//Type appropriate comment here, and begin script below
	var OUPermissions  = new GlideAjax('ClientOrganizationalScripts');
	OUPermissions.addParam('sysparm_name','checkOffice_abbreviation');
	OUPermissions.addParam("office_abbreviation", g_form.getValue('office_abbreviation'));

	OUPermissions.addParam("sys_id", g_form.getUniqueValue());

	OUPermissions.getXML(f_returnIsDuplicatea);

	function f_returnIsDuplicatea(response){
		var answer = response.responseXML.documentElement.getAttribute("answer");


		if(answer == 'true')
			g_form.showErrorBox('office_abbreviation',"The OU Abbreviation already exists.  In order to create a new OU, the OU Abbreviation must be unique.");




	}
}
